children.text:
.shadow_shower {
  display: grid;
  grid-gap: 1rem;
  grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
}
.shadow_shower div {
  height: 200px;
  background: #fff;
  border-radius: 10px;
  display: flex;
  align-items: center;
  justify-content: center;
}
.card_blur {
  height: 200px;
  position: relative;
  overflow: hidden;
}
.blur_elm {
  height: 70%; width: 70%;
  border-radius: 10px;
  position: absolute; bottom: 1%; left: 1%;
  z-index: 1;
  display: flex; align-items: center; justify-content: center;
}
.blur_img {
  height: 70%; width: 70%;
  border-radius: 10px;
  background: #3689e6;
  position: absolute; top: 1%; right: 1%;
}
.center_row { justify-content: center; }
.pad_15_row > div { margin-top: 15px; }
.col-w { color: #fff; }
.row { display:flex; flex-wrap:wrap; }
.col-xs-10 { flex:0 0 auto; width:83.333%; }
.col-sm-3 { flex:0 0 auto; width:25%; }
